import * as React from 'react';
import { Canvas } from '@react-three/fiber';
import { OrthographicCamera } from '@react-three/drei';
import { CameraRig } from '../camera/CameraRig';
import { usePlanningSelector } from '../state/world-machine';
import { MacroLayer } from '../layers/MacroLayer';
import { MesoLayer } from '../layers/MesoLayer';
import { MicroLayer } from '../layers/MicroLayer';

export function InfiniteCanvas() {
  const lod = usePlanningSelector(s => s.lod as 'macro'|'meso'|'micro');

  return (
    <div id="gl-root" className="relative w-full h-full">
      <Canvas orthographic dpr={[1, 2]} gl={{ antialias: true }}>
        <OrthographicCamera makeDefault position={[0,0,10]} />
        <CameraRig />
        {lod === 'macro' && <MacroLayer />}
        {lod === 'meso' && <MesoLayer />}
        {lod === 'micro' && <MicroLayer />}
      </Canvas>
    </div>
  );
}

