import { createSlice, createMachine } from '@mms/toolkit';
import type { SliceReducer } from '@mms/toolkit';
import { generateMockData } from '@mms/domain';
import type { Task, Conflict, Train, MockDataset } from '@mms/domain';

export type ViewMode = 'macro' | 'meso' | 'micro';

export const viewportSlice = createSlice({
  id: 'Viewport',
  cache: { policy: 'session', ttl: '12h', swr: false },
  initial: {
    zoom: 1,
    x: 0,
    y: 0,
    width: 1920,
    height: 1080,
    lod: 'meso' as ViewMode,
  },
  reducers: {
    setViewport(state, payload: { width: number; height: number }) {
      state.width = payload.width; state.height = payload.height;
    },
    setCamera(state, payload: { x?: number; y?: number; zoom?: number }) {
      state.x = payload.x ?? state.x; state.y = payload.y ?? state.y; state.zoom = payload.zoom ?? state.zoom;
      state.lod = state.zoom < 0.5 ? 'macro' : state.zoom > 2 ? 'micro' : 'meso';
    },
    panBy(state, payload: { dx: number; dy: number }) {
      state.x += payload.dx; state.y += payload.dy;
    },
    zoomBy(state, payload: { dz: number }) {
      state.zoom = Math.max(0.1, Math.min(8, state.zoom * Math.exp(payload.dz)));
      state.lod = state.zoom < 0.5 ? 'macro' : state.zoom > 2 ? 'micro' : 'meso';
    },
  },
});

export const selectionSlice = createSlice({
  id: 'Selection',
  cache: { policy: 'session', ttl: '12h', swr: false },
  initial: { hoveredId: null as string | null, selectedId: null as string | null },
  reducers: {
    setHovered(state, id: string | null) { state.hoveredId = id; },
    setSelected(state, id: string | null) { state.selectedId = id; },
  }
});

// Central dataset for all views
const initialDataset = generateMockData();

export const scheduleSlice = createSlice({
  id: 'Schedule',
  cache: { policy: 'session', ttl: '12h', swr: false },
  initial: { dataset: initialDataset as any },
  reducers: {
    regenerate(state: { dataset: any }, seed: string | undefined){
      state.dataset = generateMockData(seed);
    },
  }
});

export const conflictsSlice = createSlice({
  id: 'Conflicts',
  cache: { policy: 'session', ttl: '12h', swr: false },
  initial: { list: initialDataset.conflicts as any },
  reducers: {
    set(state, list: Conflict[]){
      state.list = list as any;
    }
  }
});

export const planningMachine = createMachine({
  id: 'Planning',
  slices: {
    viewport: viewportSlice,
    selection: selectionSlice,
    schedule: scheduleSlice,
    conflicts: conflictsSlice,
  },
  context: { userID: null },
  selectors: {
    lod: s => s.viewport.lod as ViewMode,
    zoom: s => s.viewport.zoom as number,
    camera: s => ({ x: s.viewport.x, y: s.viewport.y, zoom: s.viewport.zoom }),
    dataset: s => s.schedule.dataset,
    conflicts: s => s.conflicts.list,
  }
});

export type PlanningState = ReturnType<typeof planningMachine.getInitialState>;
export const usePlanning = planningMachine.useMachine;
export const usePlanningSelector = planningMachine.useSelector;
export const PlanningActions = planningMachine.actions;

