    37→    const list: {x:number;y:number;w:number;h:number;idx:number;id:string}[] = [];
    38→    let idx = 0;
    39→    for(const t of dataset.tasks){
    40→      if(idx>=MAX_INSTANCES) break;
    41→      const w = Math.max(2, (t.end - t.start) / (24*60*60*1000));
    42→      const x = (t.start - dataset.startTime) / (24*60*60*1000);
    43→      const y = dataset.trains.findIndex(tr => tr.id===t.trainId) * 2;
    44→      list.push({ x, y, w, h:1.5, idx, id: t.id });
    45→      idx++;
    46→    }
    47→    return list;
    48→  }, [dataset]);
