    56→
    57→    rectangles.forEach((r, i) => {
    58→      matrix.setPosition(r.x + r.w/2, r.y, 0);
    59→      matrix.scale({ x: r.w, y: r.h, z: 1 } as any);
    60→      mesh.setMatrixAt(i, matrix);
    61→      const col = new Color(r.w>6 ? '#f59e0b' : '#1d4ed8');
    62→      colorArray.set([col.r, col.g, col.b], i*3);
